public class Solution {

    public static int solve(int[] a) {
        if (a.length == 0)
            return -1;

        int index = 0;
        int biggest = 0;

        while (a.length - index > 0) {
            if (a[index] > a[biggest]) {
                biggest = index;
            }
            index = index + 1;
        }
        return biggest;
    }
}

