public class Solution {

    public static int[] solve(int arr[]) {
        int n = arr.length;

        for (int i = 0; i < n - 1; i++) {

            for (int j = 0; j < n - i - 1; j++) {
                if (arr[j + 1] < arr[j]) {
                    swap(j, j + 1, arr);
                }
            }
        }
        return arr;
    }

    private static void swap(int x, int y, int array[]) {
        int temp;
        temp = array[x];
        array[x] = array[y];
        array[y] = temp;
    }
}

