public class Solution {

  public static char solve(char c) {
    char result = ' ';
    if (c > 'z') {
      result = c;
    } else if (c >= 'a') {
      result = (char) (c - 'a' + 'A');
    } else if (c > 'Z') {
      result = c;
    } else if (c >= 'A') {
      result = (char) (c - 'A' + 'a');
    } else {
      result = c;
    }
    return result;
  }

}

