        if (overlapWidth < 0) {
            overlapWidth = 0;
        }
        if (overlapHeight < 0) {
            overlapHeight = 0;
        }
        int overlapArea = overlapHeight * overlapWidth;
        return area1 + area2 - overlapArea;
