public class Solution {

	public static int solve(int n) {
		if (n < 0)
			return -1;
		else if (n == 0)
			return 0;

		int[] fib = new int[n + 1];
		fib[0] = 0;
		fib[1] = 1;
		int index = 2;

		while (index < fib.length) {
			fib[index] = fib[index - 2] + fib[index - 1];
			index++;
		}

		return fib[n];
	}

}

