    public static int[][] solve(int[][] a, int[][] b) {

        int rows = a.length;
        int cols = b[0].length;

        int[][] c = new int[rows][cols];

        for (int i = 0; i < a.length; i++) {
            for (int j = 0; j < b[0].length; j++) {
                int sum = 0;
                for (int k = 0; k < a[0].length; k++) {
