    public static boolean solve(int n) {
        if (n <= 0) {
            return false;
        }
        int[] factors = {2, 3, 5};
        for (int i = 0; i < factors.length; i++) {
            int factor = factors[i];
            while (n % factor == 0) {
                n /= factor;
            }
        }
        return n == 1;
    }
}

